def armstrong_reflexivity(attrs):
    """If Y ⊆ X, then X → Y (trivial dependencies)"""
    return [(attrs, subset) for subset in power_set(attrs) if subset <= attrs]

def power_set(s):
    """Generate all subsets of a set"""
    from itertools import combinations
    result = [set()]
    for r in range(1, len(s) + 1):
        for combo in combinations(s, r):
            result.append(set(combo))
    return result

def armstrong_augmentation(fd, attrs_to_add):
    """If X → Y, then XZ → YZ (augmentation)"""
    lhs, rhs = fd
    return (lhs | attrs_to_add, rhs | attrs_to_add)

def armstrong_transitivity(fd1, fd2):
    """If X → Y and Y → Z, then X → Z (transitivity)"""
    lhs1, rhs1 = fd1
    lhs2, rhs2 = fd2
    if rhs1 == lhs2:
        return (lhs1, rhs2)
    return None

def derive_all_fds(initial_fds, all_attrs):
    """Derive all possible FDs using Armstrong's axioms"""
    derived = set(initial_fds)
    work_list = list(initial_fds)

    while work_list:
        fd = work_list.pop(0)

        # Apply reflexivity (add trivial dependencies)
        for trivial in armstrong_reflexivity(fd[0]):
            if trivial not in derived:
                derived.add(trivial)

        # Apply augmentation with each attribute
        for attr in all_attrs:
            aug_fd = armstrong_augmentation(fd, {attr})
            if aug_fd not in derived:
                derived.add(aug_fd)
                work_list.append(aug_fd)

        # Apply transitivity with all existing FDs
        for other_fd in derived:
            trans_fd = armstrong_transitivity(fd, other_fd)
            if trans_fd and trans_fd not in derived:
                derived.add(trans_fd)
                work_list.append(trans_fd)

    return derived

# Example: Given FDs: A → B, B → C on R(A,B,C,D)
initial_fds = [( {'A'}, {'B'} ), ( {'B'}, {'C'} )]
all_attrs = {'A', 'B', 'C', 'D'}

print("Initial FDs:")
for lhs, rhs in initial_fds:
    print(f"  {set(lhs)} → {set(rhs)}")

print("\nDerived FDs (using Armstrong's axioms):")
all_derived = derive_all_fds(initial_fds, all_attrs)
for fd in sorted(all_derived, key=lambda x: (sorted(x[0]), sorted(x[1]))):
    print(f"  {set(fd[0])} → {set(fd[1])}")

# Test transitivity: A → C (derived)
print(f"\nIs A → C derivable? {({('A',), ('C',)} in all_derived)}")
